CREATE TABLE prices (
    id INT NOT NULL AUTO_INCREMENT PRIMARY KEY,
    item VARCHAR(100),
    price DECIMAL(10,2)
) WITH SYSTEM VERSIONING;
SELECT id, price FROM prices FOR SYSTEM_TIME AS OF TIMESTAMP '2023-06-15 12:00:00';
SELECT id, price FROM prices FOR SYSTEM_TIME ALL;
SELECT id, price FROM prices FOR SYSTEM_TIME BETWEEN '2022-01-01' AND '2023-01-01';
SELECT o.id, o.status, o.created_at
FROM orders AS o FOR SYSTEM_TIME AS OF TIMESTAMP '2023-06-01 00:00:00'
JOIN customers AS c ON o.customer_id = c.id
WHERE o.id = 1;
